findings.codeql_raw_query:
/**
 * @name Code injection in ImageMath.eval
 * @description User-controlled expression strings flow to eval() in ImageMath module
 * @kind path-problem
 * @problem.severity error
 * @id py/imagemath-code-injection
 * @tags security
 *        external/cwe/cwe-094
 *        external/cwe/cwe-095
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking

module ImageMathCodeInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(Function f |
      f.getName() = "eval" and
      f.getLocation().getFile().getBaseName() = "ImageMath.py" and
      source.(DataFlow::ParameterNode).getParameter() = f.getArg(0)
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(DataFlow::CallCfgNode call |
      call.getFunction().(DataFlow::AttrRead).getAttributeName() = "eval" and
      sink = call.getArg(0)
    )
  }
}

module ImageMathCodeInjectionFlow = TaintTracking::Global<ImageMathCodeInjectionConfig>;
import ImageMathCodeInjectionFlow::PathGraph

from ImageMathCodeInjectionFlow::PathNode source, ImageMathCodeInjectionFlow::PathNode sink
where ImageMathCodeInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Expression parameter flows to eval() call from $@.", source.getNode(), "user-controlled parameter"
